@keyframes slide-up-in {
  from { transform: translateY(100%); opacity: 0; }
  to   { transform: translateY(0);    opacity: 1; }
}
@keyframes slide-up-out {
  from { transform: translateY(0);     opacity: 1; }
  to   { transform: translateY(-100%); opacity: 0; }
}

html.slide-up::view-transition-new(root) {
  animation: slide-up-in 0.4s cubic-bezier(0.25,0.46,0.45,0.94) forwards;
}
html.slide-up::view-transition-old(root) {
  animation: slide-up-out 0.4s cubic-bezier(0.25,0.46,0.45,0.94) forwards;
}

import { TransitionLink } from "@/components/transition-link"
import "./transition.css"

export function SlideUpLink({ href, children, className }: {
  href: string
  children: React.ReactNode
  className?: string
}) {
  return (
    <TransitionLink
      href={href}
      transitionClass="slide-up"
      className={className}
    >
      {children}
    </TransitionLink>
  )
}

